}

sub get_file_info {
    my ($file) = @_;
    print "\n[INFO] Gathering file information for: $file\n";
    print "-" x 50, "\n";

    # Use ls to get file details
    my $ls_output = `ls -lh "$file" 2>&1`;
    if ($? == 0) {
        print "File details:\n$ls_output";
    } else {
        warn "[WARN] Could not retrieve file details: $ls_output\n";
    }

    # Use du to get disk usage
