sub create_tar_backup {
    my ($source) = @_;
    my $archive_name = "$backup_dir/${basename}_backup_${timestamp}.tar.gz";

    print "[INFO] Creating compressed tar backup of '$source'...\n";
    write_log("Starting tar backup of '$source' -> '$archive_name'");

