        chomp $size;
        print "[INFO] Archive size: $size\n";

        return $archive_name;
    } else {
        print "[ERROR] Tar backup failed (exit code: $exit_code)\n";
        print "[ERROR] Output: $output\n";
        write_log("Backup FAILED for '$source': $output");
        return undef;
    }
}

sub create_copy_backup {
    my ($source) = @_;
    my $dest;

    if (-d $source) {
        $dest = "$backup_dir/${basename}_backup_${timestamp}";
        print "[INFO] Creating directory copy backup of '$source'...\n";
        write_log("Starting copy backup of directory '$source' -> '$dest'");

        my $ret = system("cp", "-r", $source, $dest);
        if ($ret == 0) {
            print "[SUCCESS] Directory backup created: $dest\n";
