sub generate_checksum {
    my ($file) = @_;
    print "[INFO] Generating checksums for '$file'...\n";

    # Try sha256sum first, fall back to md5sum
    my $sha256 = `sha256sum "$file" 2>&1`;
    if ($? == 0) {
        chomp $sha256;
        print "[CHECKSUM] SHA256: $sha256\n";
        write_log("SHA256 checksum for '$file': $sha256");

        # Save checksum to file
        my $checksum_file = "${file}.sha256";
        open(my $fh, '>', $checksum_file) or warn "Could not write checksum file: $!\n";
        print $fh "$sha256\n";
        close($fh);
        print "[INFO] Checksum saved to: $checksum_file\n";
    } else {
        my $md5 = `md5sum "$file" 2>&1`;
        if ($? == 0) {
            chomp $md5;
            print "[CHECKSUM] MD5: $md5\n";
            write_log("MD5 checksum for '$file': $md5");
        } else {
            print "[WARN] Could not generate checksum.\n";
        }
    }
}

sub list_archive_contents {
    my ($archive) = @_;

    unless ($archive =~ /\.tar\.gz$/ || $archive =~ /\.tgz$/) {
        print "[WARN] File does not appear to be a tar.gz archive.\n";
        return;
    }

    print "[INFO] Listing contents of '$archive':\n";
    print "-" x 50, "\n";

    my $ret = system("tar", "-tzf", $archive);
    if ($ret != 0) {
        print "[ERROR] Failed to list archive contents.\n";
    }
    print "-" x 50, "\n";
}

sub restore_backup {
    my ($archive) = @_;
    my $restore_dir = "restored_${timestamp}";

    unless (-e $archive) {
        die "[ERROR] Archive '$archive' does not exist.\n";
    }

    mkdir $restore_dir or die "Failed to create restore directory: $!\n";

    print "[INFO] Restoring '$archive' to '$restore_dir'...\n";
    write_log("Starting restore of '$archive' to '$restore_dir'");

    my $ret = system("tar", "-xzf", $archive, "-C", $restore_dir);
    if ($ret == 0) {
        print "[SUCCESS] Restored to: $restore_dir\n";
        write_log("Restore successful: $archive -> $restore_dir");

        # List restored files
        my $file_count = `find "$restore_dir" -type f | wc -l`;
        chomp $file_count;
        print "[INFO] Restored $file_count file(s).\n";
    } else {
        print "[ERROR] Restore failed.\n";
        write_log("Restore FAILED for '$archive'");
    }
}

sub cleanup_old_backups {
    my ($days) = @_;
    $days //= 30;

    print "[INFO] Cleaning up backups older than $days days...\n";
