        }
        write_log("Cleaned up " . scalar(@old_files) . " old backup(s)");
    } else {
        print "[INFO] No old backups found to clean up.\n";
    }
}

sub verify_backup {
    my ($archive) = @_;

    unless ($archive && -e $archive) {
